var d = [];
var host = 'https://www.zlykw.com';  // 建议补全域名，避免相对路径问题
var list = pdfa(getResCode(), '.stui-vodlist&&li');
for (var j in list) {
    var link = pd(list[j], 'a&&href');
    if (!link || link === '#' || link.indexOf('#') === link.length - 1) continue;  // 跳广告占位
    // 补全为绝对路径（与定首页逻辑保持一致）
    if (link && link.indexOf('http') !== 0) {
        link = host + link;
    }
    d.push({
        title: pdfh(list[j], 'a&&title'),
        desc: pdfh(list[j], '.pic-text&&Text'),
        img: pd(list[j], 'a&&data-original') + '@Referer=https://www.zlykw.com/',
        // ✅ 关键修改：添加 @rule 确保点击后进入二级解析页 er
        url: link + '#immersiveTheme##autoCache#@rule=js:$.require("er")'
    });
}
setResult(d);

